mapper.select:
select ci.id, ci.class_name, m.major_name, t.name as head_teacher_name, ci.student_count, ci.remark, ci.status from class_info ci left join major m on ci.major_id = m.id left join teacher t on ci.head_teacher_id = t.id
and ci.class_name like concat('%', #{keyword}, '%')
and ci.major_id = #{majorId}
and ci.status = #{status}
order by ci.create_time desc

mapper.update:
update class_info
class_name = #{className}, major_id = #{majorId}, head_teacher_id = #{headTeacherId}, remark = #{remark}, update_time = NOW()
where id = #{id}
